external_knowledge:
- 'Spain' refers to the country with the code 'ES'.;
- 'population over a million' means the average population is more than 1,000,000 people.;
- 'in the year 2020' includes all data points from January 1, 2020, to December 31, 2020.;

sql:
SELECT location_name, population
FROM locations
WHERE population > (SELECT AVG(population) FROM locations);

SELECT AVG(population) AS average_population
FROM locations
WHERE region_code = 'EU';

SELECT location_name
FROM locations
WHERE population > 500000 AND region_code = 'EU';
